  $gs = [System.IO.Compression.GZipStream]::new($ms, [System.IO.Compression.CompressionMode]::Decompress)
  $sr = [System.IO.StreamReader]::new($gs, [System.Text.Encoding]::UTF8)
  $jsonSIG = $sr.ReadToEnd()
