Write-Host "  statsig: OK" -ForegroundColor Gray

Write-Host ""
Write-Host "[2/4] 写入翻译文件..." -ForegroundColor Yellow
$i18nDir = "$resPath\ion-dist\i18n"
$sigDir = "$i18nDir\statsig"
[System.IO.File]::WriteAllText("$i18nDir\zh-CN.json", $jsonION, [System.Text.Encoding]::UTF8)
Write-Host "  i18n/zh-CN.json" -ForegroundColor Green
[System.IO.File]::WriteAllText("$resPath\zh-CN.json", $jsonDESK, [System.Text.Encoding]::UTF8)
Write-Host "  zh-CN.json" -ForegroundColor Green
[System.IO.File]::WriteAllText("$sigDir\zh-CN.json", $jsonSIG, [System.Text.Encoding]::UTF8)
Write-Host "  statsig/zh-CN.json" -ForegroundColor Green

Write-Host ""
Write-Host "[3/4] 注册中文语言..." -ForegroundColor Yellow
$jsFiles = Get-ChildItem "$resPath\ion-dist\assets\v1\index-*.js" -ErrorAction SilentlyContinue
$patched = $false
foreach ($jf in $jsFiles) {
  $bytes = [System.IO.File]::ReadAllBytes($jf.FullName)
  $text = [System.Text.Encoding]::UTF8.GetString($bytes)
  if ($text.Contains(Mz=["en-US","de-DE","fr-FR","ko-KR","ja-JP","es-419","es-ES","it-IT","hi-IN","pt-BR","id-ID"])) {
    $oldP = [System.Text.Encoding]::UTF8.GetBytes(Mz=["en-US","de-DE","fr-FR","ko-KR","ja-JP","es-419","es-ES","it-IT","hi-IN","pt-BR","id-ID"])
    $newP = [System.Text.Encoding]::UTF8.GetBytes(Mz=["en-US","de-DE","fr-FR","ko-KR","ja-JP","es-419","es-ES","it-IT","hi-IN","pt-BR","id-ID","zh-CN"])
    $pos = -1
    for ($i=0; $i -lt $bytes.Length-$oldP.Length; $i++) {
      $m=$true; for ($j=0; $j -lt $oldP.Length; $j++) { if ($bytes[$i+$j] -ne $oldP[$j]){$m=$false;break} }
      if ($m){$pos=$i;break}
    }
    if ($pos -ge 0) {
      $nb = New-Object byte[] ($bytes.Length+$newP.Length-$oldP.Length)
      [Array]::Copy($bytes,0,$nb,0,$pos)
      [Array]::Copy($newP,0,$nb,$pos,$newP.Length)
      [Array]::Copy($bytes,$pos+$oldP.Length,$nb,$pos+$newP.Length,$bytes.Length-$pos-$oldP.Length)
      [System.IO.File]::WriteAllBytes($jf.FullName, $nb)
      Write-Host "  JS补丁: $($jf.Name)" -ForegroundColor Green
      $patched=$true
    }
  } elseif ($text.Contains("zh-CN")) {
    Write-Host "  已注册: $($jf.Name)" -ForegroundColor Green
    $patched=$true
  }
}
if (-not $patched){Write-Host "  [警告] JS未找到" -ForegroundColor DarkYellow}

Write-Host ""
Write-Host "[4/4] 更新配置..." -ForegroundColor Yellow
$cfgs = @(
  "$env:LOCALAPPDATA\Packages\Claude_pzs8sxrjxfjjc\LocalCache\Roaming\Claude\config.json",
  "$env:LOCALAPPDATA\Packages\Claude_pzs8sxrjxfjjc\LocalCache\Roaming\Claude-3p\config.json"
)
foreach ($c in $cfgs) {
  if (Test-Path $c) {
    $j = Get-Content $c -Raw | ConvertFrom-Json
    $j.locale = "zh-CN"
    $j | ConvertTo-Json -Depth 10 | Set-Content $c -Encoding UTF8
    Write-Host "  $(Split-Path $c -Leaf)" -ForegroundColor Green
  }
}

Write-Host ""
Write-Host "========================================" -ForegroundColor Cyan
Write-Host " 安装完成! 正在重启Claude..." -ForegroundColor Green
Write-Host "========================================" -ForegroundColor Cyan

Stop-Process -Name "claude" -Force -ErrorAction SilentlyContinue
Start-Sleep -Seconds 2
if (Test-Path "$claudePath\app\claude.exe") { Start-Process "$claudePath\app\claude.exe" }
Start-Sleep -Seconds 3

Write-Host "Claude Desktop 已重启，界面应为中文" -ForegroundColor Green
Read-Host "按回车退出"